function ephDecode(arr){const out=new Array(arr.length);let v=arr[0];out[0]=v;for(let i=1;i<arr.length;i++){v+=arr[i];if(v<0)v+=3600;if(v>=3600)v-=3600;out[i]=v;}return out;}
const EPH_CACHE={};
const EPH_RAW=[D_SUN,D_MOON,D_MERCURY,D_VENUS,D_MARS,D_JUPITER,D_SATURN,D_URANUS,D_NEPTUNE,D_PLUTO];
function ephGet(p,i){if(!EPH_CACHE[p])EPH_CACHE[p]=ephDecode(EPH_RAW[p]);return EPH_CACHE[p][i]/10;}